class Solution:
    def isBipartite(self, graph: List[List[int]]) -> bool:
        color = {}
        for start in range(len(graph)):
            if start in color: continue
            stack = [(start, 0)]
            while stack:
                u, c = stack.pop()
                if u in color:
                    if color[u] != c: return False
                    continue
                color[u] = c
                for v in graph[u]:
                    stack.append((v, 1-c))
        return True

