class Solution {
public:
    bool isBipartite(vector<vector<int>>& g) {
        int n=g.size(); vector<int> col(n,-1);
        for(int s=0;s<n;s++){
            if(col[s]!=-1) continue;
            queue<int> q; q.push(s); col[s]=0;
            while(!q.empty()){
                int u=q.front(); q.pop();
                for(int v:g[u]){
                    if(col[v]==-1){ col[v]=1-col[u]; q.push(v); }
                    else if(col[v]==col[u]) return false;
                }
            }
        }
        return true;
    }
};

